const item = $input.first();
let pdfUrl = '';
if (item.json.Fichier && Array.isArray(item.json.Fichier) && item.json.Fichier[0]) {
  pdfUrl = item.json.Fichier[0].url || '';
} else if (typeof item.json.Fichier === 'string') {
  pdfUrl = item.json.Fichier;
}
return [{
  json: {
    ...item.json,
    pdfUrl,
    pdfId: item.json.id,
    pdfFilename: item.json.Nom_fichier || 'unknown.pdf'
  }
}];

const item = $input.first();
$execution.customData.set('currentPdfUrl', item.json.pdfUrl);
$execution.customData.set('currentPdfId', item.json.pdfId);
$execution.customData.set('currentPdfFilename', item.json.pdfFilename);
return $input.all();

// Clean OCR Text — normalize OCR output before grouping
const items = $input.all();
const results = [];

for (const item of items) {
  let text = item.json.extractedText || item.json.text || item.json.content || '';

  // 1. Fix common encoding artifacts
  const encodingFixes = {
    'Ã©': 'é', 'Ã¨': 'è', 'Ãª': 'ê', 'Ã«': 'ë',
    'Ã ': 'à', 'Ã¢': 'â', 'Ã®': 'î', 'Ã¯': 'ï',
    'Ã´': 'ô', 'Ã¹': 'ù', 'Ã»': 'û', 'Ã¼': 'ü',
    'Ã§': 'ç', 'Å"': 'œ', 'â€™': "'", 'â€œ': '"',
    'â€': '"', 'â€"': '—', 'â€"': '–', 'â‚¬': '€',
    '\u00A0': ' ', '\u200B': '', '\u00AD': ''
  };
  for (const [bad, good] of Object.entries(encodingFixes)) {
    text = text.split(bad).join(good);
  }

    // 1b. Strip HTML tags (e.g. <strike>415.00€</strike> → 415.00€)
  text = text.replace(/<strike>(.*?)<\/strike>/gi, '(ancien prix: $1)');
  text = text.replace(/<\/?[a-z][a-z0-9]*[^>]*>/gi, '');

  // 1c. Normalize n° formatting for consistent parsing
  text = text.replace(/n\s*°/g, 'n°');
  text = text.replace(/N\s*°/g, 'N°');

// 2. Normalize whitespace
  text = text.replace(/[ \t]{2,}/g, ' ');           // Multiple spaces → single
  text = text.replace(/\n{3,}/g, '\n\n');            // 3+ newlines → 2
  text = text.replace(/^\s+$/gm, '');                 // Blank lines with spaces

  // 3. Fix O/0 confusion in dimensions (e.g., "4OOOx3OOO" → "4000x3000")
  text = text.replace(/(\d)O(\d)/g, '$10$2');
  text = text.replace(/(\d)O(\d)/g, '$10$2');  // Second pass for consecutive
  text = text.replace(/O(\d{2,})/g, '0$1');
  text = text.replace(/(\d{2,})O/g, '$10');

  // 4. Fix l/1 confusion in numbers (e.g., "l500" → "1500" when in numeric context)
  text = text.replace(/(\d)l(\d)/g, '$11$2');
  text = text.replace(/(?<=\s|^|[:=€])l(\d{2,})/g, '1$1');

  // 5. Normalize dimension formats
  text = text.replace(/(\d+)\s*[xX×]\s*(\d+)\s*mm/g, '$1x$2mm');
  text = text.replace(/(\d+)\s*[xX×]\s*(\d+)\s*cm/g, '$1x$2cm');

  // 6. Normalize price formats: "1 500,00 €" → "1500.00 €"
  // Only in price contexts (near € or EUR or TTC or HT)
  text = text.replace(/(\d{1,3})\s(\d{3})(?=[,.]\d{2}\s*[€E])/g, '$1$2');
  text = text.replace(/(\d{1,3})\s(\d{3})\s(\d{3})(?=[,.]\d{2})/g, '$1$2$3');

  // 7. Remove repeated page markers/watermarks
  text = text.replace(/Page\s*\d+\s*(\/|sur|de)\s*\d+/gi, '');
  text = text.replace(/^(MON USINE|www\..*)$/gm, '');

  // 8. Normalize date formats for easier AI parsing
  // DD/MM/YYYY → YYYY-MM-DD
  text = text.replace(/(\d{2})\/(\d{2})\/(\d{4})/g, (m, d, mo, y) => {
    return y + '-' + mo + '-' + d + ' (orig:' + d + '/' + mo + '/' + y + ')';
  });

  results.push({
    json: {
      ...item.json,
      extractedText: text.trim(),
      text: text.trim(),
      content: text.trim()
    }
  });
}

return results;

const items = $input.all();
let pdfUrl = $execution.customData.get('currentPdfUrl') || '';
let pdfId = $execution.customData.get('currentPdfId') || '';
let pdfFilename = $execution.customData.get('currentPdfFilename') || 'unknown.pdf';

if (!items || items.length === 0) {
  return [{ json: { extractedText: 'NO DATA', invoiceIndex: 1, totalInvoices: 1, pages: [1], pageCount: 1, totalPages: 0, factureNum: '', hasFooter: false, pdfUrl, pdfId, pdfFilename } }];
}

const invoices = [];
let currentInvoice = null;

for (let i = 0; i < items.length; i++) {
  const text = items[i].json.extractedText || items[i].json.text || '';
  // Match: Facture #000004488, Facture n° 000005841, Facture n° #2508060702, Avoir n° 000000115
  const factureMatch = text.match(/(?:Facture|Avoir)\s*(?:n°\s*)?#?(\d{4,})/i);
  const factureNum = factureMatch ? factureMatch[1] : null;

  if (factureNum && (!currentInvoice || currentInvoice.factureNum !== factureNum)) {
    if (currentInvoice) invoices.push(currentInvoice);
    currentInvoice = { extractedText: text, pages: [i + 1], pageCount: 1, factureNum, totalPages: items.length };
  } else if (currentInvoice) {
    currentInvoice.extractedText += '\n\n--- Page ' + (i + 1) + ' ---\n\n' + text;
    currentInvoice.pages.push(i + 1);
    currentInvoice.pageCount++;
  } else {
    currentInvoice = { extractedText: text, pages: [i + 1], pageCount: 1, factureNum: null, totalPages: items.length };
  }
}
if (currentInvoice) invoices.push(currentInvoice);

return invoices.map((inv, idx) => ({
  json: { extractedText: inv.extractedText, invoiceIndex: idx + 1, totalInvoices: invoices.length, pages: inv.pages, pageCount: inv.pageCount, totalPages: items.length, factureNum: inv.factureNum || '', hasFooter: true, pdfUrl, pdfId, pdfFilename }
}));

const item = $input.first();
const currentPages = item.json.pages || [];
const totalPages = item.json.totalPages || 0;
const pagesToRemove = [];
for (let i = 1; i <= totalPages; i++) {
  if (!currentPages.includes(i)) pagesToRemove.push(i);
}
return [{ json: {
  pagesToRemove: pagesToRemove.join(','),
  currentPages: currentPages.join(','),
  needExtract: pagesToRemove.length > 0,
  totalPages,
  pdfUrl: item.json.pdfUrl || '',
  pdfId: item.json.pdfId || '',
  pdfFilename: item.json.pdfFilename || '',
  extractedText: item.json.extractedText || '',
  factureNum: item.json.factureNum || ''
} }];

let pdfId = "";
let pdfFilename = "processed";
let notes = "";
try {
  pdfId = $execution.customData.get("currentPdfId") || "";
  pdfFilename = $execution.customData.get("currentPdfFilename") || "processed";
} catch(e) { notes = "Read failed: " + e.message; }
if (!pdfId) {
  try {
    const gp = $("Group Pages by Invoice").first();
    pdfId = gp.json.pdfId || "";
    pdfFilename = gp.json.pdfFilename || pdfFilename;
  } catch(e) { notes += (notes ? "; " : "") + "Fallback failed"; }
}
return [{ json: { pdf_id: pdfId, pdf_filename: pdfFilename, traite: true, notes: notes || "OK", date_traitement: new Date().toISOString() } }];

const fs = require('fs');
const factureNum = ($('Prepare Invoice PDF').first().json.factureNum || 'Sans-Numero').replace(/[^a-zA-Z0-9_-]/g, '_');
const folderPath = '/home/belliard/monusine/factures/' + factureNum;
if (!fs.existsSync(folderPath)) fs.mkdirSync(folderPath, { recursive: true });
return [{ json: { folderPath, factureNum } }];

